import React, { useState } from 'react';

export default function Arr() {
    const [show, setShow] = useState(4);
    const clickToSetShow = (value) => {
        setShow((value) => value + 4);
        console.log('amount list game : ' + show)
    };

    const renderNumbers = () => {
        const numbers = [];
        for (let i = 1; i <= 5; i++) {
            numbers.push(
                <p key={i} onClick={() => clickToSetShow(i)}>
                    {i}
                </p>
            );
        }
        return numbers;
    };
    return (
        <>
            <div className="ARR-area container">
                <div className="ARR-area-head">
                    <h3>New Arrivals</h3>
                    <div className="menu-skip">
                        {renderNumbers()}
                    </div>
                </div>
                <div className="ARR-area-body">
                    <ul className="list-ARR">
                        {[...Array(show)].map((_, index) => (
                            <>
                                {show === 4 && 
                                <li key={index}>
                                    <img src="https://render.fineartamerica.com/images/rendered/default/poster/8/10/break/images/artworkimages/medium/3/3-csgo-putri-anggi.jpg" />
                                </li>
                                }
                                { show === 8 &&
                                    <li key={index}>
                                        <img src="https://i.pinimg.com/564x/b9/d9/c1/b9d9c149bcb58ef0ce6b97457e1b0468.jpg" />
                                    </li>
                                }
                                { show === 12 &&
                                    <li key={index}>
                                        <img src="https://i.pinimg.com/564x/7a/a1/c5/7aa1c5a49df9165f0c0759db71845c09.jpg" />
                                    </li>
                                }
                            </>
                        ))}
                    </ul>
                </div>

            </div>
        </>
    )
}
